          border: '1px solid rgba(10,37,64,0.06)',
          borderTop: '3px solid #00D4FF',
          borderRadius: '0 0 16px 16px',
          padding: '20px',
          boxShadow: '0 4px 12px rgba(10,37,64,0.02)'
        }}>
          {/* Header area */}
          <div style={{
            display: 'flex',
            alignItems: 'center',
            gap: '8px',
            paddingBottom: '10px',
            borderBottom: '1px solid #E6EBF1',
            marginBottom: '16px'
          }}>
