              // Basic markdown-like rendering for bold text
              const renderLine = () => {
                if (!line.includes('**')) return line
                const parts = line.split('**')
                return parts.map((part, index) => 
                  index % 2 === 1 ? <strong key={index} style={{ color: '#0A2540', fontWeight: '700' }}>{part}</strong> : part
                )
              }
              return (
                <p 
                  key={i} 
                  style={{ margin: '0 0 10px 0' }} 
                  className={`last:mb-0 ${language === 'hindi' ? 'font-hindi' : ''}`}
                >
                  {renderLine()}
                </p>
              )
            })}
          </div>
        </div>
      </div>
    </div>
  )
}

'use client'

import { useEffect, useState } from 'react'
import { IndianRupee } from 'lucide-react'
import { useLanguageStore } from '@/store/useLanguageStore'

interface TreasuryCardProps {
  savings: number
  lastUpdated?: string
}

export function TreasuryCard({ savings, lastUpdated }: TreasuryCardProps) {
  const { language } = useLanguageStore()
  const [displayValue, setDisplayValue] = useState(0)
  const [animating, setAnimating] = useState(false)

  useEffect(() => {
    const start = displayValue
    const end = savings
    if (start === end) return

    setAnimating(true)

    let startTime: number | null = null
    const duration = 1000

    const step = (timestamp: number) => {
      if (!startTime) startTime = timestamp
      const progress = Math.min((timestamp - startTime) / duration, 1)
      setDisplayValue(Math.floor(progress * (end - start) + start))
      if (progress < 1) {
        window.requestAnimationFrame(step)
      } else {
        setAnimating(false)
      }
    }

    window.requestAnimationFrame(step)
  }, [savings]) // eslint-disable-line react-hooks/exhaustive-deps

  return (
    <div
      className="relative p-5 rounded-xl bg-white border border-border-light transition-all duration-300"
      style={{
        boxShadow: animating
          ? '0 0 0 3px rgba(99,91,255,0.2), 0 4px 16px rgba(99,91,255,0.15)'
          : '0 2px 8px rgba(10,37,64,0.06)',
        borderBottom: '2px solid var(--gold)',
      }}
    >
      <div className="flex justify-between items-start mb-2">
        <h3 className={`text-stripe-muted font-medium text-sm ${language === 'hindi' ? 'font-hindi' : 'font-body'}`}>
          {language === 'hindi' ? 'कुल बचत (Jan Aushadhi)' : 'Total Savings (Jan Aushadhi)'}
        </h3>
        <div className="p-1.5 rounded-full" style={{ background: 'rgba(196,154,26,0.1)' }}>
          <IndianRupee className="w-5 h-5" style={{ color: 'var(--gold)' }} />
        </div>
      </div>

      <div className="flex items-baseline gap-1 mt-3">
        <span className="text-2xl font-bold" style={{ color: 'var(--gold)' }}>₹</span>
        <span className="text-4xl font-extrabold text-stripe-text font-body">
          {displayValue.toLocaleString('en-IN')}
        </span>
      </div>

      {lastUpdated && (
        <p className="mt-3 text-xs text-stripe-light-muted font-body">
          {language === 'hindi' ? 'आखिरी अपडेट:' : 'Last updated:'} {lastUpdated}
        </p>
      )}
    </div>
  )
}

'use client'

import Link from 'next/link'
import { User, Droplets, Calendar } from 'lucide-react'
import { FamilyMember } from '@/types/database'
import { useLanguageStore } from '@/store/useLanguageStore'

interface MemberCardProps {
  member: FamilyMember
}

export function MemberCard({ member }: MemberCardProps) {
  const { language } = useLanguageStore()

  const getRelationText = (relation: string) => {
    if (language === 'english') return relation.charAt(0).toUpperCase() + relation.slice(1)

    const relationMap: Record<string, string> = {
      'self': 'स्वयं',
      'father': 'पिता',
      'mother': 'माता',
      'child': 'बच्चा',
      'spouse': 'जीवनसाथी',
      'grandparent': 'दादा/दादी',
      'other': 'अन्य'
    }
    return relationMap[relation] || relation
  }

  // Calculate age if dob is present
  const getAge = (dob: string | null) => {
    if (!dob) return null
    const birthDate = new Date(dob)
    const today = new Date()
    let age = today.getFullYear() - birthDate.getFullYear()
    const m = today.getMonth() - birthDate.getMonth()
    if (m < 0 || (m === 0 && today.getDate() < birthDate.getDate())) {
      age--
    }
    return age
  }

  const age = getAge(member.dob)

  return (
    <Link 
      href={`/family/${member.id}`}
      className="flex flex-col bg-surface-card border border-light rounded-xl p-4 hover:border-brand-saffron transition-colors"
    >
      <div className="flex items-start gap-4">
        <div className="w-12 h-12 rounded-full bg-surface-light border border-light flex items-center justify-center text-brand-ink flex-shrink-0">
          <span className="font-display text-xl">{member.name.charAt(0).toUpperCase()}</span>
        </div>

        <div className="flex-1 min-w-0">
          <h3 className="font-body font-bold text-primary-light text-lg truncate">
            {member.name}
          </h3>
          <p className={`text-sm text-text-secondary ${language === 'hindi' ? 'font-hindi' : 'font-body'}`}>
            {getRelationText(member.relation)}
          </p>
        </div>
      </div>

      <div className="mt-4 flex gap-4 text-xs font-body text-text-secondary">
        {age !== null && (
          <div className="flex items-center gap-1.5">
            <Calendar className="w-3.5 h-3.5" />
            {age} {language === 'hindi' ? 'साल' : 'Years'}
          </div>
        )}

        {member.blood_group && (
          <div className="flex items-center gap-1.5">
            <Droplets className="w-3.5 h-3.5 text-danger" />
            <span className="font-medium text-primary-light">{member.blood_group}</span>
          </div>
        )}
      </div>
    </Link>
  )
}

'use client'

import { useEffect, useState } from 'react'
import QRCode from 'qrcode'

interface QRCodeDisplayProps {
  url: string
  size?: number
}

export function QRCodeDisplay({ url, size = 120 }: QRCodeDisplayProps) {
  const [qrCodeUrl, setQrCodeUrl] = useState<string>('')

  useEffect(() => {
    QRCode.toDataURL(url, {
      width: size,
      margin: 1,
      color: {
        dark: '#2D1F0E', // brand-ink
        light: '#FFFFFF'
      }
    })
    .then(url => {
      setQrCodeUrl(url)
    })
    .catch(err => {
      console.error(err)
    })
  }, [url, size])

  if (!qrCodeUrl) return <div style={{ width: size, height: size }} className="animate-pulse bg-gray-200" />

  return (
    <img 
      src={qrCodeUrl} 
      alt="QR Code" 
      width={size} 
      height={size}
      style={{ display: 'block' }}
    />
  )
}

'use client'

import { useEffect, useState } from 'react'
import { WifiOff } from 'lucide-react'
import { useLanguageStore } from '@/store/useLanguageStore'

export function OfflineBanner() {
  const [isOffline, setIsOffline] = useState(false)
  const { language } = useLanguageStore()

  useEffect(() => {
    // Check initial state
    setIsOffline(!navigator.onLine)

    // Listen to network changes
    const handleOnline = () => setIsOffline(false)
    const handleOffline = () => setIsOffline(true)

    window.addEventListener('online', handleOnline)
    window.addEventListener('offline', handleOffline)

    return () => {
      window.removeEventListener('online', handleOnline)
      window.removeEventListener('offline', handleOffline)
    }
  }, [])

  if (!isOffline) return null

  return (
    <div className="bg-danger text-white px-4 py-2 flex items-center justify-center gap-2 text-sm z-50 sticky top-0 md:top-auto">
      <WifiOff className="w-4 h-4" />
      <span className={language === 'hindi' ? 'font-hindi font-medium' : 'font-body font-medium'}>
        {language === 'hindi' 
          ? 'आप ऑफलाइन हैं। कुछ फीचर्स काम नहीं करेंगे।' 
          : 'You are offline. Some features may be unavailable.'}
      </span>
    </div>
  )
}

import { createServerClient, type CookieOptions } from '@supabase/ssr'
import { cookies } from 'next/headers'

export async function createClient() {
  const cookieStore = await cookies()

  return createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() {
          return cookieStore.getAll()
        },
        setAll(cookiesToSet) {
          try {
            cookiesToSet.forEach(({ name, value, options }) =>
              cookieStore.set(name, value, options)
            )
          } catch {
            // The `setAll` method was called from a Server Component.
            // This can be ignored if you have middleware refreshing
            // user sessions.
          }
        },
      },
    }
  )
}

import { createServerClient } from '@supabase/ssr'
import { NextResponse, type NextRequest } from 'next/server'

const PUBLIC_ROUTES = ['/', '/language', '/login', '/signup', '/forgot-password', '/onboarding']
const PUBLIC_PATTERN = /^\/health-card\/.+/

export async function proxy(request: NextRequest) {
  const { pathname } = request.nextUrl

  // Public routes — auth check nahi
  if (PUBLIC_ROUTES.includes(pathname) || 
      PUBLIC_PATTERN.test(pathname)) {
    return NextResponse.next()
  }

  let supabaseResponse = NextResponse.next({
    request,
  })

  // Auth check
  const supabase = createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() {
          return request.cookies.getAll()
        },
        setAll(cookiesToSet) {
          cookiesToSet.forEach(({ name, value, options }) => request.cookies.set(name, value))
          supabaseResponse = NextResponse.next({
            request,
          })
          cookiesToSet.forEach(({ name, value, options }) =>
            supabaseResponse.cookies.set(name, value, options)
          )
        },
      },
    }
  )

  const { data: { session } } = await supabase.auth.getSession()

  if (!session) {
    return NextResponse.redirect(new URL('/login', request.url))
  }

  return supabaseResponse
}

